async function runCase(activeElementFactory: (document: Document) => Element, description: string) {
  const dom = new JSDOM('<!DOCTYPE html><body><div id="target"></div></body>', { url: 'https://example.test' })
  const { window } = dom
  const target = window.document.getElementById('target')!
  let calls = 0

  const stop = onClickOutside(target, () => {
    calls += 1
  }, { window: window as any, detectIframe: true })

  await nextTick()

  const activeElement = activeElementFactory(window.document)
  Object.defineProperty(window.document, 'activeElement', {
    configurable: true,
    get: () => activeElement,
  })

  window.dispatchEvent(new window.FocusEvent('blur'))
  await flushTimers()
  stop()

  return { description, calls }
}

const normalIframe = await runCase((document) => {
  const iframe = document.createElement('iframe')
  document.body.appendChild(iframe)
  return iframe
}, 'plain iframe activeElement')

