import { JSDOM } from 'jsdom'
import { nextTick } from 'vue'
import { onClickOutside } from '../packages/core/onClickOutside/index'

async function flushTimers() {
  await new Promise(resolve => setTimeout(resolve, 10))
}

async function runCase(activeElementFactory: (document: Document) => Element, description: string) {
  const dom = new JSDOM('<!DOCTYPE html><body><div id="target"></div></body>', { url: 'https://example.test' })
  const { window } = dom
  const target = window.document.getElementById('target')!
  let calls = 0

  const stop = onClickOutside(target, () => {
    calls += 1
  }, { window: window as any, detectIframe: true })

  await nextTick()

  const activeElement = activeElementFactory(window.document)
  Object.defineProperty(window.document, 'activeElement', {
    configurable: true,
    get: () => activeElement,
  })

  window.dispatchEvent(new window.FocusEvent('blur'))
  await flushTimers()
  stop()

  return { description, calls }
}

async function main() {
  const normalIframe = await runCase((document) => {
    const iframe = document.createElement('iframe')
    document.body.appendChild(iframe)
    return iframe
  }, 'plain iframe activeElement outside target')

  const shadowIframe = await runCase((document) => {
    const host = document.createElement('custom-frame')
    const shadow = host.attachShadow({ mode: 'open' })
    const iframe = document.createElement('iframe')
    shadow.appendChild(iframe)
    document.body.appendChild(host)
    Object.defineProperty(shadow, 'activeElement', {
      configurable: true,
      get: () => iframe,
    })
    return host
  }, 'shadow host activeElement with iframe in shadowRoot outside target')

  const containedIframe = await runCase((document) => {
    const iframe = document.createElement('iframe')
    document.getElementById('target')!.appendChild(iframe)
    return iframe
  }, 'plain iframe activeElement inside target')

  const containedShadowIframe = await runCase((document) => {
    const host = document.createElement('custom-frame')
    const shadow = host.attachShadow({ mode: 'open' })
    const iframe = document.createElement('iframe')
    shadow.appendChild(iframe)
    document.getElementById('target')!.appendChild(host)
    Object.defineProperty(shadow, 'activeElement', {
      configurable: true,
      get: () => iframe,
    })
    return host
  }, 'shadow host activeElement with iframe in shadowRoot inside target')

  console.log(JSON.stringify({ normalIframe, shadowIframe, containedIframe, containedShadowIframe }, null, 2))

  if (normalIframe.calls !== 1)
    throw new Error(`Expected plain iframe outside target to trigger once, got ${normalIframe.calls}`)

  if (containedIframe.calls !== 0)
    throw new Error(`Expected plain iframe inside target not to trigger, got ${containedIframe.calls}`)

  if (containedShadowIframe.calls !== 0)
    throw new Error(`Expected shadow DOM iframe inside target not to trigger, got ${containedShadowIframe.calls}`)

  if (process.env.EXPECT_FIXED === '1') {
    if (shadowIframe.calls !== 1)
      throw new Error(`Expected shadow DOM iframe outside target to trigger once after fix, got ${shadowIframe.calls}`)
  }
  else if (shadowIframe.calls !== 0) {
    throw new Error(`Expected current bug reproduction to miss shadow DOM iframe, got ${shadowIframe.calls}`)
  }
}

main().catch((error) => {
  console.error(error)
  process.exit(1)
})
